const OPS = [{"id": "r1-48719d6f", "t": "Inteligencia fiscal de canjes para creadores — valorización automática + doble semáforo (techo y conveniencia) sobre el Plugin ARCA", "dolor": "El monotributista de contenido (influencer/CM/creativo) cobra sponsoreos por MP y transferencia y recibe canjes (productos, \"cafecitos\") que ARCA obliga a facturar a precio de mercado — pero no sabe cómo valuar el canje, no lo suma a su techo anual ($94.805.683) y en 2026 ARCA cr", "sol": "Se reutiliza 100% el Plugin ARCA (webhook MP + idempotencia por payment_id + Factura C) como base table-stakes, y el desarrollo se concentra en el net-new defendible: (1) motor de valorización de canjes a precio de mercado (FMV) con fuente de referencia; (2) acumulador de techo + semáforo verde/amarillo/rojo anticipado a la exclusión de oficio; (3) semáforo de conveniencia canj"}, {"id": "r1-eb77424c", "t": "Acuerdo Flash: contrato WhatsApp-to-confirmación para canjes y sponsoreos, con cobro y recordatorio automático", "dolor": "Marcas chicas/medianas cierran sponsoreos y canjes por WhatsApp sin nada escrito: el influencer no tiene claro entregable, fecha ni forma de cobro, y si la marca no paga o cambia a último momento no hay respaldo. Nadie de este segmento arma un contrato PDF porque \"es mucho quilom", "sol": "MVP acotado a lo mínimo vendible: (1) plantilla fija de acuerdo (sin variantes por rubro, eso va a v2), (2) parser IA que extrae los 5 campos del texto pegado/dictado, (3) página pública liviana con resumen + estado pendiente/confirmado sobre la misma infra de storefront, (4) el \"Confirmo\" dispara el recordatorio de cobro ya existente en el core. El link de cobro Mercado Pago y"}, {"id": "r1-314dbff8", "t": "Cuenta corriente de marcas — quién me debe qué, con cobro accionable por WhatsApp", "dolor": "El influencer/CM que labura con 5-10 marcas a la vez pierde el hilo de quién pagó, cuánto debe y a quién recordarle — todo desperdigado entre WhatsApp, mail y transferencias sueltas — y cuando por fin reclama, lo hace a mano, sin link de pago ni comprobante, lo que alarga el cobr", "sol": "Blueprint \"creador de contenido\" sobre el ERP core: cliente=marca/sponsor, venta=trabajo pactado (canje/posteo/reel/evento), reusando el estado de cobro parcial/total ya existente. El recordatorio se dispara desde el motor de recordatorios actual con una plantilla de mensaje que arma el link MP + adjunta comprobante ARCA cuando corresponde. La vista semáforo es una regla de col"}, {"id": "r1-36cba9d1", "t": "Media kit vivo argentinizado — el \"Stan Store\" del creador con cobro por Mercado Pago", "dolor": "Cuando una marca pide el media kit, el creador manda un PDF de Canva desactualizado (métricas viejas, tarifas en USD sin ajustar por inflación), lo edita a mano por cada cliente y no sabe si lo abrieron antes de cotizar. Y cuando cierra la colaboración, el cobro de la seña queda ", "sol": "MVP en dos capas sobre el motor multi-tenant. Capa gancho (gratis): blueprint nuevo \"Creador/Influencer\" sobre el storefront premium existente, remapeo catálogo→paquetes de contenido, reseñas del ERP→casos de éxito (sin carga manual), botón WhatsApp con el mismo deep-link que reservas, y alta por Generador de Preset por IA desde el Instagram del creador. Capa monetizable (post-"}, {"id": "r1-6cd5607b", "t": "Portal de aprobación de contenido con trazabilidad (link único, sin login) — WhatsApp-first + comprobante con validez de reclamo", "dolor": "El CM lleva 6-8 cuentas a la vez y pierde horas por semana persiguiendo aprobaciones dispersas en WhatsApp/mail, sin registro de quién aprobó qué ni cuándo. Eso genera re-trabajos, frena el cronograma de pauta y lo deja indefenso ante el clásico \"esto yo no lo aprobé\", que le com", "sol": "Nuevo blueprint sobre el motor de agenda/turnos en producción: cada \"turno\" pasa a ser una \"pieza\" con estados pendiente/aprobado/rechazado/aprobado_por_defecto, y \"profesional/cliente\" se remapea a \"marca\". Se reutiliza el motor de recordatorios WhatsApp para el aviso de pendiente y el escalamiento por silencio, el storefront/probador público para el link firmado sin login, y "}, {"id": "r1-e3883d31", "t": "El informe que se manda solo por WhatsApp y cobra el fee en el mismo link (reporte mensual branded para el CM)", "dolor": "El CM freelance arriesga la renovación mensual porque arma el reporte de resultados a mano (PowerPoint la noche antes, o no lo entrega): 3-6 hs por cliente no facturables, justo en el momento en que el cliente decide si sigue pagando el fee. El reporte es el entregable que sostie", "sol": "Endpoint + cron mensual sobre el motor de dashboards ya existente: vista \"reporte de cliente\" que reutiliza el branding por tenant, lee las tablas ya pobladas (ventas MP, storefront, WhatsApp) + los campos manuales cargados por el CM, calcula el delta vs mes anterior, llama a un preset de IA para el resumen ejecutivo en tono humano/criollo (costo $0, ADR-046) y EMBEBE el link d"}, {"id": "r1-b56139f5", "t": "Booking 1:1 con seña automática por Mercado Pago (blueprint \"Asesoría\" para el creador freelance)", "dolor": "El freelancer que vende asesorías/servicios 1:1 (edición, estrategia, foto, coaching de marca) coordina turnos a mano por WhatsApp, no cobra seña y come 20-30% de ausentismo: cada \"vengo y no aviso\" es una hora facturable perdida sin costo para quien faltó. Y cuando la sesión ter", "sol": "Blueprint nuevo \"Asesoría/Mentoría\" sobre el módulo de agenda+turnos existente (rubro estética): tipos de sesión configurables (duración/precio/% de seña), cobro de seña vía Mercado Pago ya integrado, recordatorio automático por WhatsApp con el mismo motor, y storefront público minimalista de una sola página (sin carrito/catálogo) mostrando disponibilidad y botón de reserva. De"}, {"id": "r1-cb871644", "t": "Tienda digital de presets/recursos con cobro Mercado Pago y entrega automática (entrega por WhatsApp + marca propia como diferencial)", "dolor": "El creativo vende presets/LUTs/plantillas por DM de Instagram, cobra por transferencia/alias y tiene que estar despierto para mandar el archivo a mano: pierde ventas fuera de horario, no lleva registro de qué vendió y depende de plataformas globales que cobran en dólares con tarj", "sol": "Producto \"digital\" en el catálogo (sin stock físico, con archivo/link de entrega adjunto). El webhook de pago confirmado de MP dispara la entrega automática de un link firmado con expiración/límite de descargas por email + WhatsApp, con idempotencia para no duplicar envíos. Ventas visibles en el panel existente del ERP, sin backoffice nuevo. ARCA/monotributo y value-ladder qued"}, {"id": "r1-c54de215", "t": "Pipeline de reactivación de marcas — CRM de renovación de sponsoreos", "dolor": "El influencer/CM freelance pierde renovaciones de marcas que ya lo contrataron porque no hace seguimiento sistemático: \"quién pagó, cuánto y cuándo\" vive disperso en chats viejos que nadie relee. Volver a ofrecerle a una marca conocida (con precio de referencia y relación previa)", "sol": "Reusar el módulo de clientes (entidad \"marca\" = cliente), el historial de transacciones/servicios (fecha y monto del último sponsoreo) y el motor de recordatorios del ERP, sumando un campo de estado de pipeline y una regla de recordatorio por antigüedad de última transacción (mismo patrón que \"cliente inactivo\"). El copy del mensaje sale del preset de tono argentino ya usado en"}, {"id": "r1-c435c328", "t": "Cobrá Fácil: link de cobro con marca + factura ARCA automática + persecución por WhatsApp para brandeos", "dolor": "El influencer cobra brandeos por transferencia o efectivo suelto: sin comprobante ni instrumento para exigir la seña del 50%, sin forma de reclamar el saldo cuando la marca \"se olvida\", y a fin de año sin nada que justifique ante ARCA la plata que le entró al MP/cuenta personal. ", "sol": "Se monta 100% sobre el ERP: la marca es un \"cliente\", el brandeo un \"servicio\" con condiciones de entrega, y el cobro en dos tramos usa el motor de cuotas/comisiones ya existente + Mercado Pago Link de Pago + el plugin ARCA/AFIP (monotributo) en sandbox. Se monta ENCIMA de MP, no compite su comisión. Piezas nuevas mínimas: plantilla de invoice con theming por tenant (reusa el b"}, {"id": "r1-683e69ab", "t": "CRM de marcas y pipeline de brand deals por WhatsApp (ARCA + MP + canjes, en criollo)", "dolor": "El influencer/CM negocia marcas por chat de Instagram/WhatsApp sin registro: no sabe cuánto le deben, se le vencen entregas y pierde el hilo de qué cobró; con dólar e inflación movidos, no repriza a tiempo y cobra en pesos viejos. Y ahora ARCA empieza a exigir facturar todo — inc", "sol": "Blueprint de tenant \"creador de contenido\" sobre el backoffice existente: Clientes/CRM relabeleado \"Marcas\" con campo custom de etapa tipo Kanban, Recordatorios WhatsApp-first para deadlines de entrega/cobro, vista \"total adeudado\" en el cockpit, registro de canjes, alerta de repricing >60d, y matching simple monto+fecha contra pagos de MP/transferencia para auto-marcar \"cobrad"}, {"id": "r1-b4505957", "t": "\"Media Kit Vivo\": tu carta de presentación para marcas, lista en minutos — gancho gratis del \"Stan Store argentinizado\"", "dolor": "Cuando una marca pide \"pasame tu media kit\", el creador manotea un Canva de hace 6 meses con métricas viejas o manda capturas sueltas por WhatsApp; resta seriedad justo al negociar precio y hace perder pautas frente a creadores más prolijos. El mercado lo confirma: 87% de las mar", "sol": "Se reutiliza el Generador de Preset por IA (tenant + blueprint + branding + datos demo) con un blueprint nuevo y liviano \"creador de contenido\": el creador (o su CM) da su Instagram, el sistema extrae identidad visual, nicho y posteos destacados, y arma el storefront-media kit en la URL gratuita de demo. Pasa el Gate bloqueante (SAP + GSG + Arquitectura + Confiabilidad) en Opus"}, {"id": "r1-e433359d", "t": "Aprobación de contenido sin login + comprobante de OK con validez de reclamo (WhatsApp-first, en criollo)", "dolor": "El CM que maneja 5-10 cuentas pierde horas por semana persiguiendo aprobaciones por WhatsApp/mail desordenado, y cuando el cliente reclama \"yo no aprobé esto\" no tiene evidencia (timestamp, versión, IP, identidad) para defenderse ni cobrar el retrabajo. El dolor de la disputa \"yo", "sol": "MVP acotado a 4 piezas nuevas concretas sobre lo ya existente: (1) campo de adjunto imagen/video por ítem de catálogo reusado como \"pieza\"; (2) tabla de auditoría de aprobación (timestamp+IP+identidad+versión, sin RLS nuevo, hereda tenantId); (3) botón de exportar comprobante a PDF/imagen simple (una plantilla probatoria, no un motor de reportes); (4) trigger de WhatsApp reusan"}, {"id": "r1-59635fa2", "t": "\"El informe que se manda solo y cobra en el mismo link\" — one-pager de marca por WhatsApp para el CM", "dolor": "Cada fin de mes el CM arma a mano el informe de cada cliente (3-6 hs por cliente, no facturables) en Canva/PowerPoint/planilla: queda desprolijo, distinto entre clientes y sin marca propia — justo cuando el cliente decide si renueva. Y el reporte es lo que sostiene el fee: sin RO", "sol": "MVP acotado y REPOSICIONADO: no es \"una herramienta de reportes\" (eso está comoditizado), es \"el informe que se manda solo por WhatsApp y cobra el fee en el mismo link\". Piezas: (1) plantilla visual de una página, mobile-first, con branding por tenant, reutilizable para todos los CM; (2) conector liviano a Instagram/Meta Graph API (alcance, interacciones, publicaciones, seguido"}, {"id": "r1-ef49fe09", "t": "Agenda + seña por Mercado Pago y saldo contra entrega para el creativo freelance (blueprint \"Creativo Freelance\")", "dolor": "El freelancer creativo argentino (foto, video, edición, diseño, mentorías) coordina turnos y entregas a mano por WhatsApp, sin agenda centralizada ni cobro anticipado: se le superponen sesiones de distintos clientes, se le pasan fechas de entrega y sufre 20-30% de ausentismo. En ", "sol": "Blueprint nuevo \"Creativo Freelance\" generado vía el Generador de Preset por IA sobre el módulo de Agenda existente: \"profesional\" = creativo, \"servicio\" = tipo de sesión/entrega, \"cliente\" = marca o persona contratante. Se agrega el estado \"entregado\" al modelo de turno (sin tocar el motor) para que la misma agenda funcione como tracker de entregas. Sobre la integración Mercad"}, {"id": "r1-396293e4", "t": "\"Vendé mientras dormís\": tienda de productos digitales con cobro en pesos por MP + entrega automática por WhatsApp, dentro del ERP", "dolor": "El fotógrafo/editor que ya creó un producto digital (presets, LUTs, plantillas Canva/CapCut) lo sigue vendiendo a mano: DM, espera de transferencia, comprobante, y recién ahí manda el archivo por WeTransfer o Drive. Esa fricción mata la venta impulsiva de feed/story, ata un produ", "sol": "MVP acotado: un tipo de producto \"digital\" en el Catálogo/POS existente (no descuenta stock, adjunta archivo/link seguro con token y expiración) que, al confirmarse el pago por el webhook de Mercado Pago ya operativo, dispara el envío automático del link de descarga por WhatsApp o mail y habilita un botón de descarga en la propia vidriera. Sin pasarela nueva, sin entrega manual"}, {"id": "r1-5977eaff", "t": "Cobrame — perfil de cobro con marca personal + factura ARCA automática + cobranza WhatsApp para freelancers de contenido", "dolor": "El freelancer visual cobra por transferencia o link pelado de MP: sin recibo prolijo, sin recordatorio si el cliente se demora, sin claridad de cuánto facturó al mes ni cuánto debe declarar, y con un link que no tiene su marca — resta profesionalismo justo cuando el cliente decid", "sol": "Blueprint de tenant \"freelancer/solo\" (un usuario, sin agenda ni inventario) con catálogo de servicios reducido a layout vertical link-in-bio, branding por tenant, checkout Mercado Pago, webhook de pago que dispara aviso WhatsApp y asienta el cobro en una caja simple exportable. La cuña defendible se completa con el motor de cobranza WhatsApp-first (recordatorios/persecución de"}, {"id": "r1-f416e803", "t": "Media Kit vivo + Rate Card con cobro de seña por Mercado Pago (blueprint \"Creador\" argentinizado)", "dolor": "El creador manda un PDF de media kit que envejece en dos semanas y responde a mano, por DM, la misma cotización y la coordinación de seña con cada marca. El media kit ya es requisito de facto (87% de las marcas lo exige antes de negociar), pero armarlo y mantenerlo al día es fric", "sol": "MVP acotado, sin backend nuevo: blueprint \"Creador/Influencer\" sobre el storefront público ya en producción, con el catálogo reconfigurado como \"formatos de colaboración\" (precio + % de seña), el Checkout de MP ya integrado y la agenda existente bloqueando fecha. Alta por el flujo de Preset IA (ingesta desde Instagram/web) con gate de autorización del cliente antes de publicar."}, {"id": "r1-4d9c7d42", "t": "Agenda de Aprobaciones — el CM manda el link por WhatsApp y el cliente aprueba con un toque, con comprobante que aguanta el reclamo", "dolor": "El CM freelance lleva 4 a 8 marcas a la vez y aprueba contenido a los ponchazos por WhatsApp: manda la pieza, el cliente contesta \"dale\" tres días después perdido en otro chat, y para cuando aparece ya pasó la fecha o se publicó algo que en rigor nunca estuvo aprobado. El costo r", "sol": "Se reutiliza el motor de agenda + recordatorios + gestión de clientes del ERP remapeando \"turno\" a \"pieza de contenido\" y \"cliente\" a \"cuenta gestionada\"; el link de aprobación sin password usa el mismo patrón de token público del probador (cero auth nueva). El diferencial que el mercado NO cubre entero se empaqueta acá: WhatsApp-first + comprobante con validez de reclamo + cri"}, {"id": "r1-3e2a580c", "t": "El informe que se manda solo por WhatsApp y cobra el fee en el mismo link (reporte branded + Mercado Pago para CM y agencias chicas)", "dolor": "A fin de mes el CM arma a mano en Canva/Excel el informe de cada cliente (no hay API estable de Meta/TikTok para cuentas chicas): le come 3-6 horas por cliente, son horas no facturables, y justo ese entregable es el que decide si el cliente renueva o no. Encima el reporte y el co", "sol": "Vista tipo storefront (motor de branding por tenant ya existente) con sección \\\"Reportes\\\" por cliente gestionado: el CM sube 1-3 capturas/CSV por red y por mes, la IA extrae y valida los números, genera comparativo + resumen ejecutivo, el CM aprueba con un click y se envía el link por WhatsApp con el botón de pago de Mercado Pago adentro. Guarda histórico para que desde el seg"}, {"id": "r1-7949d850", "t": "Vidriera de Descargables: catálogo digital con entrega automática por WhatsApp para creativos, dentro del ERP", "dolor": "El editor de video, diseñador o fotógrafo que vende presets de Lightroom, plantillas de Canva/CapCut o LUTs no tiene vidriera propia: cobra por transferencia, negocia por DM y manda el archivo a mano por WhatsApp o Drive, uno por uno. Cada venta exige que esté despierto y disponi", "sol": "Extender el modelo de producto del catálogo con un campo `tipoEntrega: fisico | digital`. Para \"digital\": en vez de descontar stock, el webhook de pago aprobado de Mercado Pago dispara la entrega automática — genera un link firmado con expiración desde el storage donde ya vive el archivo, y lo empuja por el mismo canal de WhatsApp que hoy usa el ERP para recordatorios/confirmac"}, {"id": "r1-70dd7163", "t": "CRM de Marcas — pipeline de sponsoreos con cotizador y cobro integrado", "dolor": "El influencer/creador argentino negocia 5-15 marcas en simultáneo por WhatsApp/DM, cotiza a ojo sin registro y no tiene un lugar único para ver qué debe entregar y qué le deben cobrar. Resultado: entregas tarde, cobros perdidos y —ahora que ARCA cruza datos y busca gravar hasta l", "sol": "MVP: (1) blueprint de mapeo cliente→marca con campos custom (contacto de prensa, historial de pago, canje vs. plata); (2) catálogo con precios sugeridos en ARS por tipo de contenido; (3) recordatorios automáticos de entrega y cobro por WhatsApp reutilizando el motor de agenda + semáforo de cobranza; (4) botón \"Facturar\" (ARCA monotributo, Factura A/E) y \"Cobrado\" (link MP/trans"}, {"id": "r1-02077435", "t": "\"Somos 3 y cobramos como 1\": el split automático para colectivos de freelas", "dolor": "Fotógrafo, editor y diseñador le facturan juntos a una marca pero reparten la guita en un Excel informal o \"después arreglamos\" — y ese después es donde se cortan sociedades: nadie tiene un registro neutral de cuánto le toca a cada uno ni de quién ya cobró. El dolor está reconoci", "sol": "Reusar el motor de comisiones + ledger de cobros de Mercado Pago que ya corre para empleados de un local, con el colectivo de freelancers como tenant y cada colaborador como \"empleado\" asignado a un proyecto puntual (ABM de asignación con % o monto fijo). Se suma: (1) vista de colaborador acotada por RBAC (solo sus propias comisiones, sin ver el resto del negocio), y (2) un est"}, {"id": "r1-68e60738", "t": "Reserva de Cupos con Seña Automática (anti doble-booking) para talleres y mentorías", "dolor": "Al vender cupos limitados de un taller o mentoría por formulario + transferencia manual, el organizador no puede bloquear el lugar en el momento del pago: dos personas pagan el mismo cupo, la conciliación es a mano contra una planilla, y si alguien cancela no hay forma automática", "sol": "MVP acotado: modelar el taller/mentoría como un \"turno de cupo único\" dentro del motor de agenda/waitlist ya existente, resolviendo el anti-doble-booking como problema transaccional (baja de cupo atómica sólo con pago acreditado). Sumar un webhook de confirmación de Mercado Pago que descuenta el cupo al acreditarse el pago (no antes), y reusar el canal de recordatorios WhatsApp"}, {"id": "r1-02516cff", "t": "Media Kit vivo del creador → \"Stan Store argentinizado\" (cobro de seña por MP + ARCA + WhatsApp)", "dolor": "Influencers y CMs freelance necesitan mandar seguido un \"media kit\" profesional (métricas, audiencia, portfolio, tarifas) a marcas para cerrar canjes/pauta, y hoy lo arman a mano en Canva/PPT: se desactualiza rápido, no tienen un link único para compartir y actualizarlo cuesta ti", "sol": "MVP en dos capas. (1) GANCHO GRATIS — Media kit vivo: landing pública tipo \"storefront\" (reutilizando el motor de vidrieras multi-tenant) por creador, con bio+foto, métricas de audiencia (carga manual simple en el MVP, sin APIs de redes), portfolio de marcas, rate card editable y botón de contacto por WhatsApp; self-serve desde un panel simple, refleja al instante en el link ún"}, {"id": "r1-d0ac604f", "t": "El informe que se manda solo por WhatsApp y cobra el fee en el mismo link", "dolor": "Todo CM con 3 a 8 cuentas llega al día 5 del mes armando el informe a las apuradas en Canva copiando números a mano (3 a 6 hs por cliente, no facturables); si un mes no sale (viaje, enfermedad, olvido) el cliente empieza a dudar si vale la pena seguir pagando. El informe no es un", "sol": "Nuevo tipo de documento sobre el motor de PDF con branding por tenant que el ERP ya usa para presupuestos/facturas. Carga 100% manual vía formulario (sin integración a APIs de Meta/TikTok en v1, para no sumar costo ni fragilidad — se evalúa en v2 solo si hay tracción paga). Disparo automático reutilizando el motor de recordatorios existente, envío final vía la integración de Wh"}, {"id": "r1-c52f8e05", "t": "Calendario editorial con aprobación por WhatsApp (comprobante de OK con validez de reclamo)", "dolor": "La aprobación de piezas con el cliente vive en mensajes sueltos y capturas de WhatsApp: no hay registro de qué se aprobó ni cuándo, y el CM termina publicando piezas no confirmadas o discutiendo \"vos me dijiste que sí\" cuando el cliente cambia de opinión. El costo real no es solo", "sol": "MVP acotado a 3 piezas nuevas sobre lo existente: (1) campo de adjunto de imagen + tipo \"contenido\" en el registro de turno/slot, (2) plantilla de WhatsApp con botones de respuesta rápida aprobada ante Meta (usa el mismo número/integración ya operativa para recordatorios), (3) webhook que mapea la respuesta del botón a los 3 estados y loguea timestamp+identidad+versión como evi"}, {"id": "r1-0101ab06", "t": "Cobrá Fácil: link de seña + factura ARCA automática para freelancers creativos", "dolor": "El fotógrafo/diseñador/editor freelance monotributista pierde plata y tiempo en dos frentes: persigue por WhatsApp a cada cliente para que pague la seña antes de arrancar el laburo, y factura tarde o no factura porque generar el comprobante en ARCA a mano le resulta engorroso, ar", "sol": "Reempaquetar el Plugin ARCA + la integración Mercado Pago (webhook de acreditación que YA dispara facturación en el ERP) + el motor de presupuestos, como producto standalone de un solo usuario. Único desarrollo real: onboarding liviano de alta de monotributista (CUIT, punto de venta, condición IVA) en 2 pasos, generador de link compartible por WhatsApp, y la vista de historial/"}, {"id": "r1-b9e0b50e", "t": "Storefront-portfolio del creativo con seña por Mercado Pago (cotizador de proyecto + WhatsApp + comprobante ARCA)", "dolor": "El freelance creativo argentino (diseñador, editor, fotógrafo, CM) no tiene tarifario público ni forma prolija de cotizar: cada DM arranca en \"¿cuánto cobrás?\" y \"¿tenés portfolio?\", pierde 15-20 min por consulta repitiendo lo mismo, con precios que la inflación desactualiza, y —", "sol": "Blueprint de rubro \"creativos/freelance por proyecto\" sobre el storefront existente: \"productos\"=servicios (\"desde\"), \"categorías\"=tipo de servicio, \"variantes\"=paquetes básico/premium. Se reutiliza casi todo (storefront + Preset IA + whatsapp-cta + cobros MP). El desarrollo real acotado: (1) blueprint del rubro; (2) extender el CTA a 3 campos con precarga; (3) wiring del flujo"}, {"id": "r1-29f48098", "t": "Copiloto fiscal del creador por WhatsApp: emite factura C + VALORIZA CANJES y semáforo de techo/conveniencia (no \"otro facturador\")", "dolor": "El monotributista creativo cobra por transferencia y recibe canjes/sponsoreos sin saber cómo valuarlos ni sumarlos a su techo, factura poco o nada, y ARCA (que en 2026 cruza datos con plataformas, bancos y tarjetas) lo puede recategorizar o excluir de oficio sin aviso — con la mu", "sol": "MVP mínimo, pivoteado al ángulo defendible: (1) webhook WhatsApp Business con parser por patrones fijos (\"facturale a [cliente] $[monto] por [concepto]\" / \"registrá canje de [marca] valor $[monto]\") — sin IA en el camino crítico; (2) reutilización directa del módulo ARCA/AFIP sandbox y MP ya operativos para emitir factura C y link de cobro, y devolver PDF por el mismo chat; (3)"}, {"id": "r1-e10c2356", "t": "Media Kit vivo + storefront de cobro argentinizado para creadores (\"Stan Store criollo\" = blueprint Influencer sobre el motor de tenants)", "dolor": "El creador cotiza por DM o con un PDF desactualizado y, cuando la marca acepta, cobrar la seña o el total sigue siendo manual (transferencia + captura por WhatsApp), sin comprobante, sin factura C/ARCA y sin registro. Pierde tiempo, consistencia de precio y a veces el cobro ni se", "sol": "Blueprint de rubro \"Creador/Influencer\" sobre infraestructura ya operativa: (1) preset IA arma la grilla de tarifas inicial desde Instagram/web; (2) paquetes de contenido como ítems del catálogo existente, asignados vía ABM de asignación (ADR-055), sin módulo nuevo; (3) botón \"Reservar\" crea orden de venta (reutiliza POS/pedidos) + preferencia MP (seña/total); (4) webhook de MP"}, {"id": "r1-a6fb749b", "t": "Agenda \"una sola persona\" con seña por Mercado Pago y saldo automático contra entrega — para fotógrafos/editores/diseñadores freelance", "dolor": "El freelance visual (fotógrafo, editor, diseñador) coordina y cobra a pulmón por WhatsApp: turnos que se pisan, seña que entra por transferencia y nadie anota (a fin de mes no sabe qué le cobró a cada cliente) y encima tiene que correr el saldo final chat por chat, en vez de que ", "sol": "(1) Blueprint de rubro \"contenido freelance\" con catálogo propio (sesión de fotos, edición, kit de diseño, mentoría); (2) RBAC colapsado a un solo profesional, sin choque de turnos; (3) regla de automatización sumada al POS existente: el estado \"entregado\" dispara el link de cobro del saldo (Mercado Pago o transferencia con conciliación); (4) vista simplificada \"mis próximos tu"}, {"id": "r1-b208e0b5", "t": "El informe que se manda solo por WhatsApp y cobra el fee en el mismo link", "dolor": "El CM freelance o de agencia chica pierde 3 a 6 horas por cliente a fin de mes armando reportes a mano en Canva/PowerPoint/planilla —horas que no factura— y encima el cobro llega separado del reporte: no hay conexión visible entre \"esto hice\" y \"esto me debés\", así que el cliente", "sol": "Extender el motor de recordatorios WhatsApp existente con un template \"reporte + cobro\": el mensaje mensual incluye un link a una página pública (patrón storefront por tenant) generada por IA con lo cargado en el catálogo del CM más una síntesis breve en tono cercano, seguido del link de pago de Mercado Pago en el MISMO mensaje. MVP 100% manual (sin scraping). Se vende como CUÑ"}, {"id": "r1-6d9e91e2", "t": "Cartera de Marcas: CRM de canjes y colaboraciones (preset Clientes+Turnos del ERP, WhatsApp + ARCA-aware)", "dolor": "El creador mid-tier y sobre todo el community manager / mini-agencia que gestiona varias cuentas maneja canjes y colaboraciones por WhatsApp sin sistema: no hay un lugar único para ver qué marca propuso qué, qué se aceptó, qué se debe entregar y cuándo. Consecuencia medible: entr", "sol": "Mapeo de 2 campos nuevos en Cliente + reuso 1:1 del modelo Turno/Reserva como \"Entrega de contenido\" + reuso del motor de recordatorios WhatsApp + preset de blueprint del rubro + 2-3 reportes de embudo/cobranza + registro de canje ARCA-aware (valorAcordado marcable para facturación). Es configuración, no módulo nuevo, sobre infraestructura ya multi-tenant en producción."}, {"id": "r1-634b5d29", "t": "Kit de marca IA para creativos: de research manual a propuesta en 10 min — reposicionado como funnel gratuito al ERP", "dolor": "El diseñador/editor/CM freelance pierde 2-4 horas NO facturadas investigando a mano rubro, paleta, tono y catálogo de un prospecto antes de mandar una propuesta que muchas veces ni se cierra, y pierde pitches contra estudios más rápidos. Encima paga Canva Pro (~AR$10.825/mes) en ", "sol": "Reusar el pipeline de extracción+generación de identidad existente (probado en Magra/Break Point) recortando el output a lo necesario para vender (moodboard/propuesta), sin catálogo/checkout/blueprint operativo. Agregar: (1) export white-label real (PDF/link con marca del creativo), (2) freemium con límite de uso + tier Pro sobre Mercado Pago, (3) tracking de conversión kit→ERP"}, {"id": "r2-a220585b", "t": "Media kit vivo argentinizado: link único que cobra la seña por Mercado Pago (storefront-as-portfolio)", "dolor": "El creativo arma a mano un PDF de media kit que queda viejo en semanas (seguidores, precios, portfolio); llega a la reunión con datos desactualizados o sin el último trabajo y pierde el pitch frente a quien manda un link prolijo y vivo. Y aun cuando cierra, cobrar la seña es un l", "sol": "Blueprint nuevo de layout (\"creador\") sobre el motor de catálogo/vidriera ya existente: renombra producto→paquete, agrega bloques de portfolio/testimonios/métricas manuales y rate card. El preset por IA arma el borrador leyendo Instagram/web (con autorización registrada, mismo flujo que Break Point/Magra); el creativo edita precios y portfolio desde el backoffice existente. Mon"}, {"id": "r2-8cdb8fc0", "t": "Turnero con seña obligatoria por Mercado Pago para creativos (foto/video/edición) — nicho freelance individual", "dolor": "El creador pierde horas facturables y plata por cancelaciones de último momento y por clientes que negocian horario a mensaje suelto de WhatsApp sin comprometerse ni pagar nada por adelantado. En sesiones de alto ticket (foto AR$30-100k, mentorías, colaboraciones con marcas) un n", "sol": "MVP acotado a config, no a desarrollo: activar el blueprint \"estudio creativo\" sobre el turnero existente (regla de seña obligatoria ya soportada por el checkout MP, timeout de liberación a 30 min ya parametrizable), dos templates nuevos (WhatsApp de recordatorio con comprobante adjunto, y copy del link público mostrando precio de seña + saldo restante en vez del genérico de pe"}, {"id": "r2-8808b1d1", "t": "Panel de cobranzas \"Mis Cuentas\" para el community manager con cartera de clientes", "dolor": "El CM freelance argentino con 5-8 cuentas no tiene un lugar único para saber quién le debe, quién pagó y quién está en mora: hoy lo lleva en un rejunte de Notion + Excel + Metricool + WhatsApp, y eso le cuesta plata real por olvidos, fees que la inflación deja viejos y el desgast", "sol": "Reutiliza al 100% lo que ya está construido y verificado en el repo: motor de clientes (Prisma Client/Payment/Invoice/Tenant), planes recurrentes, recordatorios WhatsApp, checkout y CONCILIACIÓN de Mercado Pago (src/plugins/mercadopago/cobros + reconciliation.ts) y ARCA sandbox (src/plugins/arca). El trabajo real es un blueprint nuevo \"CM/Agencia de contenido\" (nomenclatura: cu"}, {"id": "r2-07c9cbf4", "t": "Portal de aprobación de contenido con notificación por WhatsApp", "dolor": "La aprobación de piezas por WhatsApp diluye la trazabilidad: capturas duplicadas, versiones confundidas (\"la de ayer\") y ningún registro de quién aprobó qué y cuándo. Cuando algo sale mal después de publicado, el CM no tiene cómo probar que el cliente dio el visto bueno, y termin", "sol": "Módulo dentro del ERP existente: una tabla \"piezas de contenido\" (tenant-scoped) con estados (pendiente/aprobado/rechazado), historial de versiones y de quién decidió qué, siguiendo la variante ADR-055 (la pieza es un objeto con ABM propio, y la asignación cliente↔pieza es una relación explícita, nunca \"a todos con todo\"). Reutiliza el storefront público del tenant para la vist"}, {"id": "r2-8445436b", "t": "El informe que se manda solo por WhatsApp y cobra el fee en el mismo link (reporte mensual branded para CM)", "dolor": "El día 1 de cada mes el CM arma a mano en Canva/PowerPoint un informe de métricas por cada cliente (3-6 hs/cuenta, horas NO facturables); con 8-10 clientes son días perdidos, y si se atrasa el cliente no ve el trabajo del mes y duda en renovar. El reporte no es un lindo-de-tener:", "sol": "Nuevo módulo \"Reportes\" que reutiliza 100%: motor de branding por tenant (look del PDF), generación de copy por IA (resumen ejecutivo criollo), canal WhatsApp-first (envío nativo, sin stack externo), integración Mercado Pago ya existente (link de cobro del fee) y el scheduler de recordatorios (disparo día 1). Lo nuevo a construir, acotado y reversible: formulario de carga manua"}, {"id": "r2-ccea9f6b", "t": "Digital Store: presets, LUTs y plantillas en pesos, con entrega automática por WhatsApp y factura ARCA — el todo-en-uno fiscal para el creador argentino", "dolor": "Creadores que venden presets/LUTs/plantillas usan Gumroad, Payhip o Hotmart: cobran en USD con comisión 8-10%+conversión, exigen tarjeta internacional del comprador (filtra al público argentino que paga con MP/transferencia y esquiva impuesto PAIS/percepciones) y liquidan con dem", "sol": "Se marca el ítem como \\\"producto digital\\\" (sin stock/envío) en el catálogo ya existente, se reutiliza el checkout MP ya integrado, y se agrega: (1) campo de adjunto (archivo o link protegido) en la ficha, (2) webhook post-pago que dispara el link de descarga por el motor de WhatsApp/mail que ya usa el ERP para recordatorios. El watermark se resuelve con dos versiones del archi"}, {"id": "r2-55ca2623", "t": "Perfil de Creador argentinizado: media kit vivo GRATIS + storefront que COBRA (seña MP + ARCA + WhatsApp) — blueprint \"Creador\" del Generador de Preset IA", "dolor": "El creador que empieza a monetizar no tiene media kit ni forma ordenada de cobrar: manda capturas de IG por WhatsApp, cobra por transferencia sin registro y pierde acuerdos con marcas por no tener un link profesional. Hoy el 87% de las marcas exige media kit antes de negociar. La", "sol": "Reuso directo del Generador de PRESET por IA (autorización → ingesta de redes → adaptación de branding → Gate) apuntado al storefront público del ERP en modo \"perfil de creador\": catálogo = servicios/paquetes, cobro = Mercado Pago + factura C/ARCA ya integrados, contacto = WhatsApp-first ya integrado. Único desarrollo real: blueprint de rubro \"creador de contenido\" (campos de m"}, {"id": "r2-2d8b45c4", "t": "Inteligencia fiscal del creador: canjes valorizados + semáforo de techo + emisión ARCA WhatsApp-first (montado sobre el ERP)", "dolor": "El creador/CM/editor freelance monotributista no factura o factura a mano, pierde 2-4 hs/mes con ARCA, y —más grave para 2026— no sabe valuar los CANJES/sponsoreos a precio de mercado (obligatorio), no ve cuánto lo acercan al tope anual ($94.805.683) ni cuándo le conviene aceptar", "sol": "MVP mínimo vendible sobre el ERP existente: (1) blueprint 'inteligencia fiscal del creador' con catálogo de servicios digitales B2B + entidad Canje + tabla de valores de referencia FMV + parámetros de tope/categorías monotributo 2026; (2) NET-NEW: motor de valorización de canjes + acumulador anual + semáforo de techo + semáforo de conveniencia (la parte defendible que nadie cub"}, {"id": "r2-3ea737be", "t": "Booking con seña + media kit vivo para creadores argentinos (el \"Stan Store\" argentinizado)", "dolor": "El influencer/creador cierra colaboraciones por DM: manda un PDF de tarifas desactualizado, no sabe si la marca \"lo vio\" ni en qué quedó la negociación, y pierde propuestas por desorganización o porque no hay forma simple de cobrar una seña antes de bloquear agenda de grabación. ", "sol": "MVP acotado montado sobre el motor multi-tenant: (1) skin \"portfolio\" del storefront del blueprint servicios ya existente (foto grande, métricas como badges, paquetes con precio) — un layout, no una feature nueva; (2) reserva de turno + cobro de seña reusa agenda y Mercado Pago tal cual están; el estado de la propuesta se resuelve con el mismo estado de turno del ERP, sin entid"}, {"id": "r2-1bfa3333", "t": "Cartera de fee mensual para CMs: cobro por MP + recordatorio WhatsApp + conciliación automática", "dolor": "El CM freelance argentino gestiona 6-12 marcas con fee mensual (~$130.000-$300.000 c/u) cobrado por transferencia o MP y controlado a mano en Excel/Notion. El atraso de cobro (10-15 días) es plata que la inflación se come, el reclamo por WhatsApp se posterga o se olvida, y las tr", "sol": "Reusa el módulo de Clientes + Cobros + Recordatorios del ERP (blueprint servicios) reconfigurado con el objeto \"cliente de gestión de redes\" con fee mensual en vez de turno. Se apalanca la integración MP ya viva (link de cobro + webhook), el canal WhatsApp-first ya integrado (recordatorio + confirmación por tap) y el motor de recordatorios (cron), solo redefiniendo el trigger a"}, {"id": "r2-0afa0b44", "t": "El informe que se manda solo por WhatsApp (y cobra el fee en el mismo link)", "dolor": "Todo fin de mes el CM pierde 2-3 horas por cliente armando a mano un PDF en Canva con capturas de Instagram/TikTok para justificar el fee; si se atrasa un día, el cliente ya pregunta \"¿y los resultados?\" y un mes de laburo real queda en duda por un informe, no por el trabajo en s", "sol": "MVP acotado dentro del panel del CM/agencia en el ERP: (1) un formulario simple para cargar las 4-5 métricas del mes por cliente (carga manual, sin integración de APIs sociales en esta v1); (2) el motor de reportes/branding ya existente arma el PDF con la marca del cliente final; (3) IA genera el resumen en lenguaje llano y criollo (\"creciste 8% en seguidores, tu pico fue el re"}, {"id": "r2-a506ea10", "t": "Vidriera de Infoproductos: presets, plantillas y mentorías con cobro en pesos, entrega por WhatsApp y factura ARCA automática", "dolor": "El creador que vende presets, plantillas o mentorías 1:1 no tiene dónde mostrarlos con estética de marca (queda preso del Linktree feo o del post fijado), pierde 10-20% de comisión y cobra en dólares vía Hotmart/Gumroad (fricción de tarjeta internacional, impuesto PAIS/percepcion", "sol": "Cada infoproducto se carga como producto de catálogo con stock ilimitado y tipo \"entrega digital\". Al confirmarse el pago de MP, un webhook dispara: (a) para preset/plantilla, el envío automático del link de descarga por WhatsApp (y email de respaldo); (b) para mentoría 1:1, la redirección al módulo de agenda existente para que el comprador reserve su horario; (c) en ambos caso"}, {"id": "r2-2cb95082", "t": "\"Che, ¿ya me depositaste?\" — nunca más: cobrás con factura y sin perseguir a nadie", "dolor": "El freelancer creativo no tiene problema de precio sino de cobranza: cotiza a mano por WhatsApp, después queda a merced del \"ya te transfiero\" que se diluye, y cuando cobra, la mitad de las veces no factura (vergüenza de pedir el CUIT, pereza de entrar al portal de ARCA), dejando", "sol": "Blueprint \"freelancer-creativo\" sobre el core existente: onboarding de 10 minutos (nombre, CUIT monotributo, WhatsApp Business), catálogo corto de servicios predefinidos, orden de cobro en 2 taps que dispara link de MP por WhatsApp y factura ARCA automática al acreditarse, recordatorio automático a 48hs si no pagó, y panel semáforo cobrado/pendiente/vencido. Se monta ENCIMA de "}, {"id": "r2-4716d9dc", "t": "Media Kit vivo argentinizado: rate card + booking con seña por Mercado Pago + lead a WhatsApp (blueprint \"Creador\")", "dolor": "El influencer cotiza colaboraciones a mano con un PDF/Canva desactualizado por DM, sin precios visibles ni canal formal de cotización, pierde el seguimiento del lead frente a marcas que evalúan varios perfiles a la vez — y cuando cierra, cobra la seña por transferencia suelta sin", "sol": "Blueprint \"Creador/Influencer\" sobre el motor de storefront existente: \"producto\" pasa a \"paquete de colaboración\" (nombre, formato, precio, descripción), se agrega bloque de métricas manuales por red (actualización mensual vía formulario) y — corrección clave respecto de la v2 — NO se saca Mercado Pago: se conserva el cobro para tomar SEÑA de reserva, se mantiene el hook ARCA "}, {"id": "r2-7e31cdc4", "t": "Blindaje de seña: agenda de colaboraciones con marcas + seña por Mercado Pago (con saldo automático contra entrega)", "dolor": "El creador coordina grabaciones y entregas con 3-5 marcas en paralelo a mano por WhatsApp: sin agenda centralizada dobla fechas, se le pisan entregas, y arranca a producir sin cobrar seña — así queda plata afuera cuando la marca cancela o corre el shooting a último momento. En co", "sol": "Blueprint \"colaboraciones\" derivado 1:1 del Blueprint de servicios, mismo motor de Agenda+Recordatorios+Cobros, blanco distinto: (1) rename turno→colaboración y profesional→marca en textos y storefront/backoffice vía branding por tenant; (2) 2 campos nuevos en el modelo existente (tipo de contenido: reel/foto/story/UGC; fecha de entrega de contenido, distinta de la fecha de gra"}, {"id": "r2-173d9dc0", "t": "El informe que se manda solo por WhatsApp y cobra el fee en el mismo link (marca del CM)", "dolor": "El CM freelance/agencia chica en Argentina cobra ARS 300.000-450.000 por cuenta/mes y lleva 4-10 clientes; a fin de mes pierde 3-6 hs POR CLIENTE armando a mano en Canva/PowerPoint/planilla el informe que \"justifica\" el fee — trabajo que no factura pero cuya ausencia dispara duda", "sol": "Tenant \"Estudio CM\": cada cliente del CM es una cuenta con un formulario simple de carga mensual (alcance, engagement, seguidores, etc.). El motor de IA (costo US$0) redacta el resumen ejecutivo en tono humano/criollo (zona humana, ADR-046); el storefront ya pinta la página con la marca del CM (branding multi-tenant); el motor de recordatorios/WhatsApp existente dispara el enví"}, {"id": "r2-938fc27d", "t": "\"Comprá y listo\": link de pago para presets, plantillas y mentorías que se entrega solo por WhatsApp", "dolor": "El creativo que vende presets, plantillas o cupos de mentoría 1:1 depende de transferencia + \"ahora te paso el link\" manual: pierde ventas fuera de horario, no controla la reventa/clonado del archivo, y se le mezclan los cupos de mentoría hasta agendar doble. Encima, si ya factur", "sol": "Se trata cada infoproducto como ítem del catálogo/inventario existente: trackStock=false para archivos ilimitados (preset, LUTs, plantilla) o trackStock=true con stock chico para cupos de mentoría/curso en vivo. Al acreditarse el pago vía webhook de Mercado Pago (ya integrado), se dispara un envío de WhatsApp (reusa el módulo de mensajería/recordatorios) con el archivo adjunto "}, {"id": "r2-1dc2026c", "t": "CRM de marcas: pipeline de negociaciones para influencers (WhatsApp + ARCA + canje)", "dolor": "El influencer/CM maneja 10-20 negociaciones simultáneas por DM/WhatsApp sin registro estructurado: no sabe cuánto ofreció cada marca, en qué etapa quedó, ni cuándo hacer seguimiento — resultado en propuestas que se enfrían, colaboraciones cerradas de palabra que nunca se facturan", "sol": "Reutilizar el módulo de clientes: cada \"marca\" es un cliente con `etapaNegociacion` (enum: Contacto/Propuesta enviada/En negociación/Cerrado/Cobrado), `montoNegociado` y `esCanje`. Vista kanban liviana sobre la lista de clientes existente con semáforo de cobranza. El motor de recordatorios WhatsApp ya construido se reconfigura con la regla \"sin actividad en la ficha por N días\""}, {"id": "r2-28821f03", "t": "Media Kit vivo argentinizado: link único siempre al día + cobro de seña por Mercado Pago (no un armador más, un \"Stan Store criollo\")", "dolor": "El creador argentino cotiza por WhatsApp y manda media kits en PDF que envejecen solos: precios viejos por la inflación, stats viejas. Pierde horas reescribiendo el PDF y pierde pauta cuando manda una tarifa que ya no rige. Y cuando cierra, cobrar la seña y facturar (Factura C/AR", "sol": "Reutilizar el motor de storefront/vidriera y el módulo de catálogo/precios (ABM ya existente) para armar un blueprint nuevo \"Creador/Influencer\": página pública con bio, foto, métricas editables a mano y tabla de paquetes con precio y botón de WhatsApp por ítem. Sobre eso, cablear los módulos que el ERP ya tiene — seña por Mercado Pago, factura C/ARCA (sandbox) y lead a WhatsAp"}, {"id": "r2-66b63a73", "t": "El informe que la marca pide y el cobro que vos necesitás, se manda solo por WhatsApp en un solo link", "dolor": "Terminada la campaña, el influencer/CM pierde media tarde armando un Canva/PDF con capturas y métricas para \"justificar\" el pago (3-6 hs por cliente a fin de mes, horas no facturables), y después persigue por WhatsApp los datos de cobro y el comprobante — sin factura ni recibo pr", "sol": "Nuevo tipo de documento \"Informe de campaña\" sobre el módulo de clientes (la marca ya existe como cliente) y el de facturación/cobros ya construido: arriba, secciones editables de contenido (imágenes + KPIs manuales cargados a mano, sin integrarse a la API de Meta); abajo, botón \"Generar factura ARCA\" o \"Generar recibo\" + botón \"Crear link de pago MP\". Un solo link corto, con v"}, {"id": "r2-8f413934", "t": "Agenda de Aprobaciones: calendario de contenido con OK por WhatsApp y comprobante de reclamo (agenda del ERP reconvertida)", "dolor": "El CM maneja 5-10 cuentas con calendarios dispersos (Excel/Notion/Drive) y aprueba piezas por WhatsApp a los manotazos: capturas, \"sí dale\", \"cambiá el texto\", sin registro de qué quedó aprobado, cuándo y en qué versión. Cuando el cliente después dice \"yo nunca aprobé eso\", el CM", "sol": "MVP acotado: una vista \"Aprobaciones\" (tablero kanban por estado) dentro del backoffice del CM, más una landing pública de aprobación sin contraseña (mismo patrón que el storefront). Se reutiliza el motor de agenda/turnos (estado+fecha) y los recordatorios automáticos por WhatsApp. El trabajo real: (1) agregar el objeto \"pieza de contenido\" con su ABM propio (adjunto/preview, c"}, {"id": "r2-81f29db5", "t": "Storefront-portfolio con cotizador de proyecto y seña por Mercado Pago para creativos freelance", "dolor": "El creativo freelance (diseñador, editor, fotógrafo) cotiza y cobra por DM/WhatsApp con un link de Mercado Pago suelto: no queda registro único de qué cliente pagó seña, qué pack o proyecto contrató y para cuándo. Pierde profesionalismo, se le mezclan pedidos y no puede emitir co", "sol": "MVP acotado montado 100% sobre el motor existente: (1) blueprint visual \"portfolio creativo\" (galería grande, sin grilla de góndola) por el Generador de Preset IA; (2) ocultar el campo \"stock\" (el servicio creativo no tiene stock) y habilitar un campo \"seña/cotización\" por pack; (3) delta real vs los tenants de turnos: flujo de PROYECTO por-cotización (no por turno-y-hora) que "}, {"id": "r2-cd683b64", "t": "Panel de gestión multi-cliente para community managers (mini-ERP por CM)", "dolor": "El CM freelance argentino que lleva 5-8 cuentas cobra por transferencia/MP sin orden, factura tarde o no factura, y cuando el cliente pregunta \"¿me mandaste el reporte de este mes?\" lo busca en un Excel viejo o scrolleando WhatsApp para atrás. Cuatro herramientas sueltas (Excel, ", "sol": "Combina 4 módulos ya existentes (CRM, recordatorios WhatsApp, cobros/ARCA/MP, agenda resignificada como calendario editorial) vía el Generador de Preset por IA — solo vocabulario (cliente→marca, turno→contenido, servicio→plan), sin tocar backend ni construir conectores a APIs de redes sociales (el riesgo/costo real que se evita). MVP mínimo vendible: preset + 1 flujo de demo (a"}, {"id": "r2-c4b98d24", "t": "Copiloto fiscal del creador: canjes valorizados + semáforo de techo (ARCA/MP por WhatsApp)", "dolor": "El monotributista de contenido cobra por transferencia, MP y plataformas del exterior, y encima recibe CANJES y sponsoreos que ARCA obliga a facturar a precio de mercado. No sabe cómo valuar el canje, no lleva registro mes a mes y vive con miedo a pasarse del techo y que ARCA lo ", "sol": "Capa conversacional liviana (parser de intents, sin IA cara) sobre tres piezas que el ERP ya tiene pagas — ARCA sandbox, Mercado Pago, WhatsApp Business — MÁS el diferenciador net-new que se construye nuevo: un ABM de canje (objeto canje + asignación, ADR-055) con motor de valorización a precio de mercado, y el motor de semáforos (techo + conveniencia). Se vende como add-on del"}, {"id": "r2-23d733ab", "t": "Cotizador con cobro integrado (seña Mercado Pago) para creadores — sobre el storefront ya existente", "dolor": "Cuando una marca escribe por DM, el creador no tiene tarifa fija por formato (reel, story, posteo, canje): cotiza \"a ojo\" por chat, sin trazabilidad. Si cierra el trato, no tiene forma prolija de cobrar la seña ni de dejar constancia de la venta, y todo queda perdido en una captu", "sol": "MVP acotado a lo mínimo vendible, 100% sobre módulos existentes: (1) catálogo de servicio relabeled a \"formatos de contenido\" con precio ARS, reusando el módulo de catálogo; (2) botón de cotización self-serve en el storefront público que arma el presupuesto sin que el creador tenga que escribir primero; (3) link de cobro de Mercado Pago embebido en el mismo PDF para cobrar seña"}, {"id": "r2-19f2ad3b", "t": "CRM de marcas con semáforo de cobranza y timeline visual de entregables", "dolor": "El community manager/creador gestiona 5-15 marcas en simultáneo entre Excel, WhatsApp y notas sueltas: no tiene un solo lugar donde ver de un vistazo qué le deben, qué tiene que entregar y para cuándo. El dolor es de visibilidad de un vistazo, no solo de caja — y ahora se agrava ", "sol": "MVP acotado a reutilización: renombrar jerga del módulo clientes+agenda+recordatorios WhatsApp del ERP (clientes=marcas, turnos=entregas/reuniones), agregar un componente de semáforo de cobro (reutilizando el patrón de badges/estados ya existente) y una vista Kanban simple sobre los mismos datos de agenda/tareas. El link \"vista cliente\" reutiliza el mecanismo de storefront públ"}, {"id": "r2-7e27f8c7", "t": "El informe que se manda solo por WhatsApp y cobra el fee en el mismo link", "dolor": "El 28 de cada mes el CM que lleva 3-4 cuentas se pone a las 23hs a copiar y pegar capturas en Canva para armar el informe del cliente. Lo manda tarde, con errores, o directamente lo debe y el cliente empieza a preguntar en qué se le está gastando la plata. No es falta de resultad", "sol": "Reutilizar el motor de reportes periódicos + generación de PDF del ERP (hoy corre para ventas/POS) cambiando la fuente de datos: en vez de tickets de venta, toma los ítems del calendario editorial como \\\"entregas\\\", agrupadas por cliente y contadas por tipo de pieza. Un cron mensual por tenant arma el PDF automático el último día del mes, le aplica el branding del cliente final"}, {"id": "r2-eb20121a", "t": "Registro de canjes con valorización automática y semáforo de conveniencia", "dolor": "Las colaboraciones en canje (no en plata) con marcas chicas/medianas son la norma en Argentina, y el creador no tiene forma simple de valorizar lo recibido a precio de mercado, comparar si conviene frente a su tarifa en efectivo, ni dejarlo asentado para el monotributo. Hoy lo ll", "sol": "MVP acotado: (1) nuevo tipo de comprobante \"Canje\" con 4-5 campos (marca, producto/servicio, cantidad, referencia de precio de catálogo o valor manual, tipo de publicación acordada); (2) cálculo automático del valor en pesos y comparación contra la tarifa vigente del creador para ese tipo de publicación, con semáforo simple de conveniencia sin cálculo manual; (3) el registro ca"}, {"id": "r2-f83e3508", "t": "Kit de Piezas Gráficas de Marca — imán gratuito desde el motor de PRESET IA del ERP", "dolor": "Freelancers, community managers e influencers necesitan piezas gráficas coherentes con su marca (portada de historias, media kit, presupuesto/factura, banner de promo, firma de WhatsApp) todo el tiempo, pero no tienen diseñador fijo ni Canva Pro (~AR$10.825/mes que muchos ni banc", "sol": "MVP acotado a 5 piezas (no 8) usando el pipeline de extracción de identidad ya existente + una capa nueva de templates fijos (SVG/HTML→PNG/PDF) parametrizados por logo/paleta/tono extraídos. Sin editor visual, sin variantes por rubro en v1 — un set único de templates genéricos que sirve para cualquier creativo. Entrega por ZIP descargable + captura de email/WhatsApp del lead an"}, {"id": "af-facturacion-arca-monotributo-new", "t": "Escudo de Canje — acuerdo bilateral creador↔marca + carpeta probatoria de valor de mercado + simulacro de defensa ante cruce/exclusión de ARCA", "dolor": "El creador acepta canjes/sponsoreos y (con el producto del cluster) ya los valúa y factura. Pero el dolor NUEVO de 2026 no es valuar: es SOBREVIVIR AL CRUCE. ARCA recategoriza y excluye de oficio de forma automática cruzando facturación electrónica vs. acreditaciones bancarias vs", "sol": "Escudo de Canje, tres piezas: (1) ACUERDO DE CANJE bilateral creador↔marca — entregables, plazos, FMV pactado y cláusula fiscal de que cada parte factura su lado (justo lo que la marca necesita para deducir), firmable por WhatsApp/email con sello de tiempo; (2) CARPETA PROBATORIA por canje — captura fechada del precio de lista/e-commerce del producto (evidencia del valor de mer"}, {"id": "af-cobranzas-link-pago-freelance-new", "t": "Exportá y Cobrá — cobro del exterior en USD con Factura E automática y compliance del ingreso de divisas", "dolor": "El freelancer argentino que le factura a un cliente del exterior (un CM que maneja una marca de afuera, un diseñador con estudio en USA/EU, un creativo con clientes globales) arma un Frankenstein todavía peor que el doméstico: cobra en USD por Payoneer/Wise/transferencia/USDC, de", "sol": "Sobre la base ya existente del ERP (integración ARCA en sandbox, MP, WhatsApp, storefront con branding por tenant y RBAC multi-tenant), se agrega un módulo \"Exportación de servicios\": (a) emisión de comprobante tipo E vía WSFEX/WSFE de ARCA en USD con cotización, (b) feed de tipo de cambio oficial BNA para valuar y mostrar el equivalente en ARS, (c) intake de cobro USD multi-ra"}, {"id": "af-gestion-cartera-cm-new", "t": "Cerrá Cliente — el front-door del CM: cotización + propuesta/contrato firmable + primer cobro MP + factura ARCA", "dolor": "El CM freelance argentino pierde clientes en la puerta y trabaja gratis las primeras semanas: cotiza a mano por WhatsApp, manda un audio o un PDF armado en Canva sin propuesta ni contrato, tarda en cerrar, arranca sin seña y muchas veces sin factura. Se ve amateur justo cuando má", "sol": "Wedge de front-door que reutiliza la infra del ERP (MP + ARCA + WhatsApp + branding por tenant): (1) Cotizador con plantillas por rubro CM (gestión de redes, pack de contenido, campaña, retainer) y fee configurable en pesos; (2) Propuesta compartible por link con la marca del CM, alcance, entregables y condiciones; (3) Aceptación con un clic con sello de tiempo/registro = mini-"}, {"id": "af-media-kit-rate-card-new", "t": "Panel de Colaboraciones del Creador: CRM de canjes + Semáforo de monotributo/ARCA (el motor detrás del media kit)", "dolor": "El media kit ya está comoditizado y regalado: captura el lead, pero después el creador queda solo con el lío real. Cada colaboración/canje se le desparrama entre DMs, notas del celu y capturas: no sabe qué marca le debe, qué tiene que entregar ni cuándo cobró. Y encima el terror ", "sol": "Sobre el motor multi-tenant existente, blueprint \"Creador\": (1) Datos maestros Marca como objeto con ABM propio (ADR-055 VARIANTE) y Colaboración como relación con su propio ABM; (2) Pipeline kanban de colabs reusando el engine de turnos/pedidos, con estados y recordatorios WhatsApp-first de entregas y cobros; (3) Semáforo de Monotributo: acumulador de facturación anual por ten"}, {"id": "af-vidriera-portfolio-cotizador-new", "t": "Cobralo por Hitos — cobranza escalonada con entrega bloqueada por pago para proyectos creativos", "dolor": "El creativo que trabaja por proyecto cobra la seña y ahí termina la ayuda: después corre atrás del SALDO. \"Ya entregué el laburo y no me pagan la otra mitad\" es EL dolor del freelance argentino. Las apps de turnos (ReservaSimple, TurnoSmart, Zlog) resuelven un único depósito al r", "sol": "Plugin \"Cobralo por Hitos\" del ERP: (1) ABM de proyecto con hitos (dato maestro + relación, estilo ADR-055) — cada hito tiene monto/ARS, disparador (aprobación, avance, entrega) y % del total; (2) orquestación multi-cobro sobre el webhook MP existente — cada hito genera su link de pago, su estado y su reintento; (3) comprobante ARCA por hito reutilizando arca-dispatch; (4) reco"}, {"id": "af-crm-marcas-sponsoreos-new", "t": "Canje Legal: valuador de canjes + guardián del monotributo (ARCA) para creadores", "dolor": "El creador argentino recibe canjes (un bolso, una estadía, una cena, productos) a cambio de contenido y NO los valúa, NO los factura y NO sabe que ARCA los considera permuta gravada al valor de mercado del bien recibido. Peor: ese canje SUMA al tope anual del monotributo. Resulta", "sol": "1) ABM de Canje como dato maestro (ADR-055): qué se recibió, marca, fecha, entregables comprometidos, y valuación en pesos (sugerida desde catálogo/precio de referencia + edición manual). 2) Facturación de la permuta: genera la Factura E/A del servicio publicitario y registra la contrapartida, ARCA-aware (sandbox primero). 3) Guardián del monotributo: acumulador rodante efectiv"}, {"id": "af-aprobacion-contenido-new", "t": "Testigo — el sello probatorio SOBRE el WhatsApp que ya existe (sin portal) + pre-vuelo IA que baja las rondas de rechazo", "dolor": "El CM/creativo argentino ya recibe el \"dale, va\" del cliente EN el chat de WhatsApp real, informal. No quiere migrar a otro portal ni mandar links: quiere que ESE \"sí\" que ya ocurrió tenga valor cuando el cliente después reclame (\"yo no aprobé eso\", \"no era esta versión\", \"no te ", "sol": "Mecánica diferenciada del cluster: en vez de RELOCALIZAR la aprobación a un link/portal tokenizado, se CERTIFICA la aprobación donde naturalmente ocurre (WhatsApp nativo). El número Testigo de GSG queda en el hilo y sella mensajes en el momento de captura (no retroactivo sobre screenshots, que no prueban), con hash + timestamp de autoridad + identidad del emisor. On-demand gene"}, {"id": "af-reportes-mensuales-resultados-new", "t": "Captura y listo: el informe del mes SIN conectar ninguna cuenta — el CM manda la captura por WhatsApp y le vuelve el reporte con la marca de su cliente (y el link de cobro)", "dolor": "El muro no es armar el informe: es CONECTAR la cuenta. Todos los incumbentes (Metricool, Porter, Reportei) exigen enganchar el Instagram del cliente vía Meta Graph API + una Facebook Page linkeada + permisos en Business Manager. El micro-CM argentino (1-10 clientes) casi nunca ti", "sol": "Flujo en 3 toques: (1) el CM reenvía por WhatsApp las capturas de Insights del mes (propias o que le pasó el cliente); (2) la IA multimodal extrae las métricas, el CM valida/corrige en una pantalla simple (control de exactitud), y elige el cliente/marca; (3) GSG genera el informe branded (identidad del cliente vía preset) y lo devuelve por WhatsApp listo para reenviar, con link"}, {"id": "af-agenda-booking-sena-new", "t": "Cuenta Corriente Creativa: abono recurrente con seña por Mercado Pago y saldo blindado que se libera contra cada entrega (WhatsApp-first)", "dolor": "El creativo freelance que ya tiene clientes/marcas RECURRENTES (no el turno suelto) cobra a los tirones: renegocia seña en cada pieza, persigue el saldo por WhatsApp, no tiene una cuenta clara de \"cuánto me debe / cuánto adelantó\" ese cliente, y cuando una marca frena el mes se l", "sol": "Máquina de estados reserva→seña cobrada→entrega→aprobación→liberación de saldo, montada sobre agenda/clientes/cobros/MP que el ERP ya tiene. Se agrega: (1) wallet/cuenta corriente por cliente con movimientos (adelanto, consumo, saldo, deuda); (2) abono/retainer mensual con auto-recarga; (3) liberación de saldo atada al evento de entrega aprobada, no a la fecha; (4) blindaje: la"}, {"id": "af-tienda-productos-digitales-new", "t": "Círculo — Membresías y mentorías recurrentes del creador: cobro en pesos por MP, Factura C automática recurrente y acceso por WhatsApp, dentro del ERP con marca propia", "dolor": "El creador argentino ya sabe vender el preset de $5 una vez (Pulgy y DropyFile le resolvieron el cobro+entrega one-shot). El problema es que ahí se termina: cada mes arranca de cero cazando ventas sueltas. El ingreso recurrente —la membresía, el círculo de mentoría, el \"club de e", "sol": "Cuatro piezas net-new sobre la fundación existente: (1) Dato maestro \"Plan de membresía / Mentoría recurrente\" con ABM propio y ABM de asignación tier↔beneficio↔tenant (principio de VARIANTE, ADR-055 — nada de \"a todos con todo\"). (2) Cobro recurrente nativo con MP Suscripciones/preapproval: alta de plan, suscripción por link WhatsApp, webhooks de cobro recurrente, reintentos y"}, {"id": "af-preset-ia-piezas-graficas-new", "t": "Marca Viva — motor de identidad persistente que argentiniza y auto-aplica la marca real del cliente a TODO el ERP y sus comunicaciones", "dolor": "El creador recibe un brand kit estático (Looka/Canva/Brandmark) que muere en una carpeta: su tienda, sus tickets, sus mensajes de WhatsApp, sus recordatorios y sus piezas promo NO quedan consistentes con su marca, y menos cuando su catálogo y su feed cambian cada semana. Las tool", "sol": "Motor de tokens de marca + theming engine multi-tenant. (1) Reutiliza la ingesta IG/web del Preset por IA para extraer identidad real → la normaliza a un set versionado de tokens de marca por tenant. (2) Un theming engine aplica esos tokens, por tenantId, al storefront y al backoffice (CSS variables/design tokens, sin fork del Core). (3) Un generador de piezas templiza salidas "}]

const ITEM = {
  type: 'object',
  properties: {
    id: { type: 'string' },
    criollo: { type: 'string', description: 'Qué es y para qué sirve, en 1-2 frases SIN tecnicismos, como se lo explicarías a un amigo que no sabe nada de tecnología ni de fiscal. Nada de "blueprint", "storefront", "RLS", "idempotencia", "MVP" — palabras de la calle.' },
    comoGana: { type: 'string', description: 'Cómo hace plata (el creador o GSG) en una frase criolla y concreta.' },
  },
  required: ['id', 'criollo', 'comoGana'],
}
const BATCH = { type: 'object', properties: { items: { type: 'array', items: ITEM } }, required: ['items'] }

function chunk(a, n) { const o = []; for (let i = 0; i < a.length; i += n) o.push(a.slice(i, i + n)); return o }
const lotes = chunk(OPS, 13)

phase('Criollo')
log(`Traduciendo ${OPS.length} oportunidades a criollo, sin tecnicismos, en ${lotes.length} lotes.`)
const out = await parallel(lotes.map((lote, i) => () =>
  agent(
    `Sos un comunicador argentino que explica cosas complicadas fácil, con calidez y sin vueltas (zona HUMANA/criolla, ADR-046 de GSG). Te paso oportunidades de negocio para creadores de contenido, escritas con jerga técnica y fiscal. Reescribí CADA una en criollo: en 1-2 frases, qué es y para qué sirve, como se lo contarías a un amigo que no sabe nada de sistemas ni de impuestos. Sacá TODO tecnicismo (blueprint, storefront, RLS, idempotencia, webhook, MVP, ARCA→decí "la AFIP/la parte de facturar", etc.). Sumá "comoGana": cómo se hace plata, en una frase concreta. No exageres ni prometas de más; hablá claro y humano.\n\nOPORTUNIDADES (lote ${i + 1}/${lotes.length}):\n${JSON.stringify(lote, null, 1)}`,
    { label: `criollo:lote-${i + 1}`, phase: 'Criollo', schema: BATCH, effort: 'low' }
  )
))
const map = {}
out.filter(Boolean).forEach(r => (r.items || []).forEach(it => { if (it && it.id) map[it.id] = { criollo: it.criollo, comoGana: it.comoGana } }))
log(`Traducidas ${Object.keys(map).length}/${OPS.length}.`)
return { criollo: map }
